const data = $input.first().json;
console.log('Full data:', JSON.stringify(data));

const message = data.message;
console.log('Message:', JSON.stringify(message));

return [{ json: { debug: data } }];

const httpData = $('HTTP Request').first().json;

if (!httpData || !httpData.values) {
  return [{ json: { error: 'No sheet data', ...$('Code in JavaScript').first().json } }];
}

const rows = httpData.values;
const headers = rows[0];
const telegramId = $('Code in JavaScript').first().json.telegram_id;

const match = rows.slice(1).find(row => String(row[0]) === String(telegramId));

if (match) {
  const client = {};
  headers.forEach((header, i) => {
    client[header] = match[i] || '';
  });
  return [{
    json: {
      ...$('Code in JavaScript').first().json,
      client_id: match[3] || 'Unknown',
      client_name: match[1] || 'Unknown',
      client_found: true,
      client_instructions: match[5] || '',
    }
  }];
} else {
  return [{
    json: {
      ...$('Code in JavaScript').first().json,
      client_found: false,
      client_id: 'UNKNOWN',
      client_name: 'Unknown Sender'
    }
  }];
}
